 2→
 3→export const onRequest = createPressyMiddleware((env) => ({
 4→  sendEmail: async ({ to, subject, html }) => {
 5→    console.log("Sending email to:", to);
 6→    console.log("Subject:", subject);
 7→    console.log("HTML:", html);
 8→    console.log("RESEND_API_KEY:", env.RESEND_API_KEY);
 9→
10→    const resp = await fetch("https://api.resend.com/emails", {
11→      method: "POST",
12→      headers: {
13→        Authorization: `Bearer ${env.RESEND_API_KEY}`,
14→        "Content-Type": "application/json",
15→      },
16→      body: JSON.stringify({ from: env.EMAIL_FROM, to: [to], subject, html }),
17→    });
18→
19→    if (!resp.ok) {
20→      const body = await resp.text();
21→      console.error("Failed to send email:", resp.status, body);
22→      throw new Error(`Failed to send email: ${resp.status} ${body}`);
23→    }
24→
25→    console.log("Email sent successfully");
26→    return resp.json();
27→  },
28→}));
