186→  if (!('serviceWorker' in navigator) || !navigator.serviceWorker.controller) {
187→    return
188→  }
189→
190→  navigator.serviceWorker.controller.postMessage({
191→    type: 'GET_CACHE_STATUS',
192→    urls: urls.map((url) =>
193→      url.startsWith('http') ? url : `${window.location.origin}${url}`
194→    ),
195→  })
