198→// Clear cached book
199→export async function clearBookCache(bookSlug: string): Promise<boolean> {
200→  // Update state and persist immediately
201→  const newCached = new Set(cachedBooks.value)
202→  newCached.delete(bookSlug)
203→  cachedBooks.value = newCached
204→  persistCachedBooks()
205→
206→  if (!('serviceWorker' in navigator) || !navigator.serviceWorker.controller) {
207→    // Fallback to direct cache API
208→    try {
209→      const cache = await caches.open('pressy-offline-books')
210→      const keys = await cache.keys()
211→
212→      for (const request of keys) {
213→        if (request.url.includes(`/books/${bookSlug}`)) {
214→          await cache.delete(request)
215→        }
216→      }
217→
218→      return true
219→    } catch (err) {
220→      console.error('Failed to clear cache:', err)
221→      return false
222→    }
223→  }
224→
225→  // Prefer message-based approach so SW can coordinate
226→  navigator.serviceWorker.controller.postMessage({
227→    type: 'CLEAR_BOOK_CACHE',
228→    bookSlug,
229→  })
230→  return true
231→}
