 31→function matchChapterRoute(pathname: string): { bookSlug: string; chapterSlug: string } | null {
 32→  // Match /books/{bookSlug}/{chapterSlug} with optional trailing slash
 33→  const match = pathname.match(/^\/books\/([^/]+)\/([^/]+)\/?$/)
 34→  if (!match) return null
 35→  return { bookSlug: match[1], chapterSlug: match[2] }
 36→}
 37→
 38→function isChapterPaid(
 39→  book: PressyBookManifest,
 40→  chapterSlug: string,
 41→): boolean {
 42→  if (!book.paywall?.enabled) return false
 43→
 44→  const chapter = book.chapters.find((ch) => ch.slug === chapterSlug)
 45→  if (!chapter) return false
 46→
 47→  return chapter.order >= book.paywall.previewChapters
 48→}
 49→
 50→async function isAuthorized(
 51→  request: Request,
 52→  bookSlug: string,
 53→  secret: string,
 54→): Promise<boolean> {
 55→  const cookieHeader = request.headers.get('cookie')
 56→  if (!cookieHeader) return false
 57→
 58→  const cookies = parseCookies(cookieHeader)
 59→  const authCookie = cookies[cookieName(bookSlug)]
 60→  if (!authCookie) return false
 61→
 62→  const payload = await verifyCookie(authCookie, secret)
 63→  return payload !== null && payload.book === bookSlug
 64→}
 65→
 66→/**
 67→ * KV-based rate limiter. Returns true if the request should be blocked.
 68→ */
 69→async function rateLimit(
 70→  kv: KVNamespace,
 71→  key: string,
 72→  limit: number,
 73→  windowSec: number,
 74→): Promise<boolean> {
 75→  const rlKey = `ratelimit:${key}`
 76→  const existing = await kv.get(rlKey)
 77→  const count = existing ? parseInt(existing, 10) : 0
 78→
 79→  if (count >= limit) return true
 80→
 81→  await kv.put(rlKey, String(count + 1), { expirationTtl: windowSec })
 82→  return false
 83→}
 84→
 85→function getClientIp(request: Request): string {
 86→  return request.headers.get('cf-connecting-ip')
 87→    || request.headers.get('x-forwarded-for')?.split(',')[0]?.trim()
 88→    || 'unknown'
 89→}
 90→
 91→function addSecurityHeaders(response: Response): Response {
 92→  const newHeaders = new Headers(response.headers)
 93→  for (const [k, v] of Object.entries(SECURITY_HEADERS)) {
 94→    newHeaders.set(k, v)
 95→  }
 96→  return new Response(response.body, {
 97→    status: response.status,
 98→    statusText: response.statusText,
 99→    headers: newHeaders,
100→  })
101→}
102→
103→function methodNotAllowed(): Response {
104→  return new Response('Method not allowed', { status: 405, headers: { ...NO_CACHE, ...SECURITY_HEADERS } })
105→}
106→
107→/** Minimal subset of Cloudflare Pages EventContext that the middleware uses. */
108→export interface PressyContext {
109→  request: Request
110→  env: Env
111→  next: () => Promise<Response>
112→}
113→
114→export function createPressyMiddleware(
115→  optionsOrFactory?: PressyMiddlewareOptions | ((env: Env & Record<string, unknown>) => PressyMiddlewareOptions),
116→) {
117→  return async (context: PressyContext): Promise<Response> => {
118→    const { request, env, next } = context
119→    const url = new URL(request.url)
120→    const pathname = url.pathname
121→
122→    const options: PressyMiddlewareOptions = typeof optionsOrFactory === 'function'
123→      ? optionsOrFactory(env as Env & Record<string, unknown>)
124→      : optionsOrFactory ?? {}
125→
126→    // Route API requests
127→    if (pathname.startsWith('/api/')) {
128→      const response = await handleApiRoute(request, env, pathname, url, options)
129→      return addSecurityHeaders(response)
130→    }
131→
132→    // Check if this is a chapter URL that needs paywall enforcement
133→    const chapterMatch = matchChapterRoute(pathname)
134→    if (!chapterMatch) {
135→      return next()
136→    }
137→
138→    let manifest: PressyManifest
139→    try {
140→      manifest = await loadManifest(env)
141→    } catch {
142→      // If manifest can't be loaded, pass through
143→      return next()
144→    }
145→
146→    const book = manifest.books.find((b) => b.slug === chapterMatch.bookSlug)
147→    if (!book) {
148→      return next()
149→    }
150→
151→    if (!isChapterPaid(book, chapterMatch.chapterSlug)) {
152→      return next()
153→    }
154→
155→    // Chapter is paid — check authorization
156→    const authorized = await isAuthorized(request, book.slug, env.COOKIE_SECRET)
157→    if (authorized) {
158→      return next()
159→    }
160→
161→    // Not authorized — redirect to book page with purchase prompt
162→    return new Response(null, {
163→      status: 302,
164→      headers: { Location: `/books/${book.slug}/?purchase=true`, ...NO_CACHE },
165→    })
166→  }
167→}
168→
169→function missingEnvError(...names: string[]): Response {
170→  const hint = names.map((n) => `wrangler pages secret put ${n}`).join(', ')
171→  return new Response(
172→    JSON.stringify({ error: `Missing required environment variable(s): ${names.join(', ')}. Set via: ${hint}` }),
173→    { status: 500, headers: { 'Content-Type': 'application/json', ...NO_CACHE } },
174→  )
175→}
176→
177→// Route → allowed method(s) mapping
178→const ROUTE_METHODS: Record<string, string> = {
179→  '/api/checkout': 'GET',
180→  '/api/stripe-webhook': 'POST',
181→  '/api/auth/callback': 'GET',
182→  '/api/auth/status': 'GET',
183→  '/api/auth/recover': 'POST',
184→  '/api/auth/verify': 'GET',
185→}
186→
187→async function handleApiRoute(
188→  request: Request,
189→  env: Env,
190→  pathname: string,
191→  url: URL,
192→  options: PressyMiddlewareOptions,
193→): Promise<Response> {
194→  // Method enforcement
195→  const allowedMethod = ROUTE_METHODS[pathname]
196→  if (allowedMethod && request.method !== allowedMethod) {
197→    return methodNotAllowed()
198→  }
199→
200→  // Rate limiting for auth endpoints
201→  if (pathname.startsWith('/api/auth/')) {
202→    const ip = getClientIp(request)
203→    const blocked = await rateLimit(env.PRESSY_KV, `auth:${ip}`, 60, 60)
204→    if (blocked) {
205→      return new Response('Too many requests', { status: 429, headers: NO_CACHE })
206→    }
207→  }
208→
209→  let manifest: PressyManifest
210→  try {
211→    manifest = await loadManifest(env)
212→  } catch {
213→    return new Response('Manifest not found', { status: 500 })
214→  }
215→
216→  // GET /api/checkout?book=SLUG
217→  if (pathname === '/api/checkout') {
218→    if (!env.STRIPE_SECRET_KEY) return missingEnvError('STRIPE_SECRET_KEY')
219→    const bookSlug = url.searchParams.get('book')
220→    if (!bookSlug) {
221→      return new Response('Missing book parameter', { status: 400 })
222→    }
223→    const book = manifest.books.find((b) => b.slug === bookSlug)
224→    if (!book) {
225→      return new Response('Book not found', { status: 404 })
226→    }
227→    return handleCheckout(request, env, book)
228→  }
229→
230→  // POST /api/stripe-webhook
231→  if (pathname === '/api/stripe-webhook') {
232→    if (!env.STRIPE_SECRET_KEY) return missingEnvError('STRIPE_SECRET_KEY')
233→    if (!env.STRIPE_WEBHOOK_SECRET) return missingEnvError('STRIPE_WEBHOOK_SECRET')
234→    return handleWebhook(request, env)
235→  }
236→
237→  // GET /api/auth/callback?session_id=xxx (single-use post-checkout redirect)
238→  if (pathname === '/api/auth/callback') {
239→    if (!env.STRIPE_SECRET_KEY) return missingEnvError('STRIPE_SECRET_KEY')
240→    if (!env.COOKIE_SECRET) return missingEnvError('COOKIE_SECRET')
241→    return handleAuthCallback(request, env, manifest)
242→  }
243→
244→  // GET /api/auth/status?book=SLUG
245→  if (pathname === '/api/auth/status') {
246→    if (!env.COOKIE_SECRET) return missingEnvError('COOKIE_SECRET')
247→    const bookSlug = url.searchParams.get('book')
248→    if (!bookSlug) {
249→      return new Response(JSON.stringify({ authorized: false }), {
250→        headers: { 'Content-Type': 'application/json', ...NO_CACHE },
251→      })
252→    }
253→    const authorized = await isAuthorized(request, bookSlug, env.COOKIE_SECRET)
254→    return handleAuthStatus(request, env, authorized)
255→  }
256→
257→  // POST /api/auth/recover — sends magic link email
258→  if (pathname === '/api/auth/recover') {
259→    if (!env.COOKIE_SECRET) return missingEnvError('COOKIE_SECRET')
260→
261→    // Stricter rate limit for recover: 3 per 15 minutes per email
262→    try {
263→      const body = await request.clone().json() as { email?: string }
264→      const email = body.email?.trim().toLowerCase()
265→      if (email) {
266→        const emailBlocked = await rateLimit(env.PRESSY_KV, `recover:${email}`, 3, 15 * 60)
267→        if (emailBlocked) {
268→          return new Response('Too many requests', { status: 429, headers: NO_CACHE })
269→        }
270→      }
271→    } catch {
272→      // Body parse error will be handled by handleRecoverPurchase
273→    }
274→
275→    return handleRecoverPurchase(request, env, manifest, options.sendEmail)
276→  }
277→
278→  // GET /api/auth/verify?token=xxx — validates magic link, issues cookie
279→  if (pathname === '/api/auth/verify') {
280→    if (!env.COOKIE_SECRET) return missingEnvError('COOKIE_SECRET')
281→    return handleVerifyToken(request, env, manifest)
282→  }
283→
284→  return new Response('Not found', { status: 404 })
285→}
286→

  1→import { useSignal } from '@preact/signals'
  2→
  3→export interface PaywallProps {
  4→  bookSlug: string
  5→  bookTitle: string
  6→  previewChapters: number
  7→  currentChapter: number
  8→  shopifyProductId?: string
  9→  mode?: 'shopify' | 'email'
 10→  onUnlock?: () => void
 11→}
 12→
 13→export function Paywall({
 14→  bookSlug,
 15→  bookTitle,
 16→  previewChapters,
 17→  currentChapter,
 18→  shopifyProductId,
 19→  mode = 'email',
 20→  onUnlock,
 21→}: PaywallProps) {
 22→  const email = useSignal('')
 23→  const isLoading = useSignal(false)
 24→  const error = useSignal('')
 25→  const isUnlocked = useSignal(false)
 26→
 27→  // Check if already unlocked
 28→  if (typeof window !== 'undefined') {
 29→    const unlocked = localStorage.getItem(`pressy-unlocked-${bookSlug}`)
 30→    if (unlocked) {
 31→      isUnlocked.value = true
 32→    }
 33→  }
 34→
 35→  if (isUnlocked.value) {
 36→    return null
 37→  }
 38→
 39→  // Show paywall if past preview chapters
 40→  if (currentChapter <= previewChapters) {
 41→    return null
 42→  }
 43→
 44→  const handleEmailSubmit = async (e: Event) => {
 45→    e.preventDefault()
 46→
 47→    if (!email.value || !email.value.includes('@')) {
 48→      error.value = 'Please enter a valid email address'
 49→      return
 50→    }
 51→
 52→    isLoading.value = true
 53→    error.value = ''
 54→
 55→    try {
 56→      // In a real implementation, this would send to a backend
 57→      // For now, just unlock locally
 58→      await new Promise((resolve) => setTimeout(resolve, 1000))
 59→
 60→      localStorage.setItem(`pressy-unlocked-${bookSlug}`, 'email')
 61→      localStorage.setItem(`pressy-email-${bookSlug}`, email.value)
 62→
 63→      isUnlocked.value = true
 64→      onUnlock?.()
 65→    } catch (err) {
 66→      error.value = 'Something went wrong. Please try again.'
 67→    } finally {
 68→      isLoading.value = false
 69→    }
 70→  }
 71→
 72→  const handleShopifyPurchase = async () => {
 73→    if (!shopifyProductId) {
 74→      error.value = 'Purchase not available'
 75→      return
 76→    }
 77→
 78→    isLoading.value = true
 79→
 80→    try {
 81→      // This would integrate with @pressy-pub/shopify
 82→      // For now, just show that it would redirect
 83→      const { createCheckout } = await import('@pressy-pub/shopify' as string)
 84→      const checkoutUrl = await createCheckout(shopifyProductId)
 85→      window.location.href = checkoutUrl
 86→    } catch (err) {
 87→      error.value = 'Failed to create checkout. Please try again.'
 88→      isLoading.value = false
 89→    }
 90→  }
 91→
 92→  return (
 93→    <div class="pressy-paywall">
 94→      <div class="pressy-paywall-content">
 95→        <div class="pressy-paywall-icon">
 96→          <svg width="48" height="48" viewBox="0 0 24 24" fill="currentColor">
 97→            <path d="M18 8h-1V6c0-2.76-2.24-5-5-5S7 3.24 7 6v2H6c-1.1 0-2 .9-2 2v10c0 1.1.9 2 2 2h12c1.1 0 2-.9 2-2V10c0-1.1-.9-2-2-2zm-6 9c-1.1 0-2-.9-2-2s.9-2 2-2 2 .9 2 2-.9 2-2 2zm3.1-9H8.9V6c0-1.71 1.39-3.1 3.1-3.1 1.71 0 3.1 1.39 3.1 3.1v2z" />
 98→          </svg>
 99→        </div>
100→
101→        <h2 class="pressy-paywall-title">Continue Reading</h2>
102→        <p class="pressy-paywall-description">
103→          You've enjoyed the first {previewChapters} chapters of "{bookTitle}".
104→          {mode === 'shopify'
105→            ? ' Purchase the full book to continue reading.'
106→            : ' Enter your email to unlock the full book.'}
107→        </p>
108→
109→        {mode === 'email' ? (
110→          <form class="pressy-paywall-form" onSubmit={handleEmailSubmit}>
111→            <input
112→              type="email"
113→              placeholder="Enter your email"
114→              value={email.value}
115→              onInput={(e) => (email.value = (e.target as HTMLInputElement).value)}
116→              class="pressy-paywall-input"
117→              disabled={isLoading.value}
118→            />
119→            <button type="submit" class="pressy-paywall-button" disabled={isLoading.value}>
120→              {isLoading.value ? 'Unlocking...' : 'Unlock Full Book'}
121→            </button>
122→          </form>
123→        ) : (
124→          <button
125→            class="pressy-paywall-button pressy-paywall-purchase"
126→            onClick={handleShopifyPurchase}
127→            disabled={isLoading.value}
128→          >
129→            {isLoading.value ? 'Processing...' : 'Purchase Now'}
130→          </button>
131→        )}
132→
133→        {error.value && <p class="pressy-paywall-error">{error.value}</p>}
134→
135→        <p class="pressy-paywall-note">
136→          {mode === 'email'
137→            ? "We'll never share your email with anyone."
138→            : 'Secure checkout powered by Shopify.'}
139→        </p>
140→      </div>
141→
142→      <style>{`
143→        .pressy-paywall {
144→          position: fixed;
145→          inset: 0;
146→          background: rgba(0, 0, 0, 0.8);
147→          display: flex;
148→          align-items: center;
149→          justify-content: center;
150→          z-index: 1000;
151→          padding: 1.5rem;
152→        }
153→
154→        .pressy-paywall-content {
155→          background: var(--color-bg);
156→          border-radius: 1rem;
157→          padding: 2.5rem;
158→          max-width: 400px;
159→          width: 100%;
160→          text-align: center;
161→        }
162→
163→        .pressy-paywall-icon {
164→          color: var(--color-accent);
165→          margin-bottom: 1.5rem;
166→        }
167→
168→        .pressy-paywall-title {
169→          font-size: var(--font-size-xl);
170→          font-weight: 600;
171→          margin-bottom: 0.75rem;
172→          color: var(--color-heading);
173→        }
174→
175→        .pressy-paywall-description {
176→          color: var(--color-text-muted);
177→          margin-bottom: 1.5rem;
178→          line-height: 1.5;
179→        }
180→
181→        .pressy-paywall-form {
182→          display: flex;
183→          flex-direction: column;
184→          gap: 0.75rem;
185→        }
186→
187→        .pressy-paywall-input {
188→          width: 100%;
189→          padding: 0.875rem 1rem;
190→          border: 1px solid var(--color-border);
191→          border-radius: 0.5rem;
192→          font-size: var(--font-size-base);
193→          background: var(--color-bg);
194→          color: var(--color-text);
195→        }
196→
197→        .pressy-paywall-input:focus {
198→          outline: none;
199→          border-color: var(--color-accent);
200→          box-shadow: 0 0 0 3px rgba(0, 102, 204, 0.1);
201→        }
202→
203→        .pressy-paywall-button {
204→          width: 100%;
205→          padding: 0.875rem 1rem;
206→          border: none;
207→          border-radius: 0.5rem;
208→          font-size: var(--font-size-base);
209→          font-weight: 500;
210→          background: var(--color-accent);
211→          color: white;
212→          cursor: pointer;
213→          transition: opacity 0.15s;
214→        }
215→
216→        .pressy-paywall-button:hover:not(:disabled) {
217→          opacity: 0.9;
218→        }
219→
220→        .pressy-paywall-button:disabled {
221→          opacity: 0.6;
222→          cursor: not-allowed;
223→        }
224→
225→        .pressy-paywall-error {
226→          color: #dc2626;
227→          font-size: var(--font-size-sm);
228→          margin-top: 0.75rem;
229→        }
230→
231→        .pressy-paywall-note {
232→          font-size: var(--font-size-sm);
233→          color: var(--color-text-muted);
234→          margin-top: 1.5rem;
235→        }
236→      `}</style>
237→    </div>
238→  )
239→}
